// JVM进程内缓存 vs 分布式缓存对比
// 存储位置：JVM Heap vs 独立缓存服务器
// 可见范围：仅当前进程 vs 所有进程/集群
// 访问速度：纳秒/微秒级 vs 毫秒级
// 数据一致性：多实例可能不一致 vs 天然一致
// 容量限制：单机JVM Heap vs 可横向扩展
// 生命周期：随进程重启丢失 vs 持久化/独立存在

// 多级缓存读取流程
public Object getData(String key) {
    // L1: JVM本地缓存
    Object value = caffeineCache.getIfPresent(key);
    if (value != null) return value;

    // L2: Redis分布式缓存
    value = redisTemplate.opsForValue().get(key);
    if (value != null) {
        caffeineCache.put(key, value);  // 回写到JVM缓存
        return value;
    }

    // L3: 数据库
    value = db.query(key);
    redisTemplate.opsForValue().set(key, value);
    caffeineCache.put(key, value);
    return value;
}

