-- common.lua 封装
local function read_http(path, params)
    local resp = ngx.location.capture(path, {
        method = ngx.HTTP_GET,
        args = params,
    })
    if not resp then
        ngx.log(ngx.ERR, "http not found")
        ngx.exit(404)
    end
    return resp.body
end
local _M = { read_http = read_http }
return _M

